const expectedHighlights = [
    [0, 1], [1, 2], [2, 3], [3, 4],
    [0, 1], [1, 2], [2, 3], [3, 4],
    [0, 1], [1, 2], [2, 3], [3, 4],
    null
];
const genBtn = document.querySelector("#generate-btn");
const sortBtn = document.querySelector("#sort-btn");
const randomMocker = new __helpers.RandomMocker();
randomMocker.mock();
try{
    genBtn.dispatchEvent(new Event("click"));
    sortBtn.dispatchEvent(new Event("click"));

    const container = document.getElementById("array-container");
    const divs = Array.from(container.children);
    const redBorderRegex = /dashed (rgb\(255,\s*0,\s*0\)|#FF0000|hsl\(0,\s*100%,\s*50%\))/;

    divs.forEach((div, i) => {
        const children = Array.from(div.children);
        if(expectedHighlights[i]){
            const [index1, index2] = expectedHighlights[i];
            assert.match(getComputedStyle(children[index1]).border, redBorderRegex);
            assert.match(getComputedStyle(children[index2]).border, redBorderRegex);
        }
    })
} finally {
    randomMocker.restore();
}

